 1→export type HeadersLike =
 2→  | Headers
 3→  | Record<string, string | string[] | undefined>
 4→  | Iterable<[string, string | string[] | undefined]>;
 5→
 6→/**
 7→ * Convert object to Headers instance.
 8→ */
 9→export function toHeaders(headersLike: HeadersLike = {}): Headers {
10→  if (headersLike instanceof Headers) return headersLike;
11→
12→  const headers = new Headers();
13→  for (const [key, value] of Object.entries(headersLike)) {
14→    if (Array.isArray(value)) {
15→      value.forEach((val) => headers.append(key, val));
16→    } else if (value !== undefined) {
17→      headers.set(key, value);
18→    }
19→  }
20→
21→  return headers;
22→}
