 1→/**
 2→ * Schema to match the request.
 3→ */
 4→
 5→// serializable
 6→export type MockRequestSchema = {
 7→  /**
 8→   * The pattern to match the request URL.
 9→   */
10→  url: string;
11→  /**
12→   * Pattern type:
13→   * - 'urlpattern': match request URL by URLPattern (default).
14→   * - 'regexp': match request URL by regular expression.
15→   */
16→  patternType?: 'urlpattern' | 'regexp';
17→  /**
18→   * The request method for matching.
19→   */
20→  method?: HttpMethod;
21→  /**
22→   * The query parameters for matching, defined as key-value pairs.
23→   */
24→  query?: Record<string, string | number | null>;
25→  /**
26→   * The request headers for matching, defined as key-value pairs.
27→   */
28→  headers?: Record<string, string | null>;
29→  /**
30→   * The request body for matching, defined as a string or JSON.
31→   */
32→  body?: string | Record<string, unknown> | Array<unknown>;
33→  /**
34→   * Flag to output debug info on server.
35→   */
36→  debug?: boolean;
37→};
38→
39→export type MockRequestSchemaInit =
40→  | string
41→  | RegExp
42→  | {
43→      url: string | RegExp;
44→      patternType?: MockRequestSchema['patternType'];
45→      method?: MockRequestSchema['method'];
46→      query?: MockRequestSchema['query'];
47→      headers?: MockRequestSchema['headers'];
48→      body?: MockRequestSchema['body'];
49→      debug?: MockRequestSchema['debug'];
50→    };
51→
52→export function buildMockRequestSchema(init: MockRequestSchemaInit): MockRequestSchema {
53→  const initObj = toMockRequestSchemaObject(init);
54→  const { url, ...rest } = initObj;
55→
56→  if (url instanceof RegExp) rest.patternType = 'regexp';
57→
58→  // always convert url to string to handle regexp
59→  const urlStr = url.toString();
60→
61→  return Object.assign({ url: urlStr }, rest);
62→}
63→
64→export function toMockRequestSchemaObject(init: MockRequestSchemaInit) {
65→  if (!init) throw new Error('Request schema cannot be empty.');
66→
67→  return typeof init === 'string' || init instanceof RegExp ? { url: init } : init;
68→}
69→
70→type HttpMethod =
71→  | 'GET'
72→  | 'HEAD'
73→  | 'POST'
74→  | 'PUT'
75→  | 'DELETE'
76→  | 'CONNECT'
77→  | 'OPTIONS'
78→  | 'TRACE'
79→  | 'PATCH';
80→

 1→/**
 2→ * Schema to generate the response.
 3→ */
 4→
 5→// serializable
 6→export type MockResponseSchema = {
 7→  /**
 8→   * The HTTP status code, default is 200.
 9→   */
10→  status?: number;
11→  /**
12→   * The response headers, defined as key-value pairs.
13→   */
14→  headers?: Record<string, string>;
15→  /**
16→   * The response body, defined as a string or JSON.
17→   */
18→  body?: string | null | Record<string, unknown> | Array<unknown>;
19→  /**
20→   * The response body patch, defined as a key-value pairs.
21→   * If defined, the real request will be sent, and the response will be patched.
22→   * Not compatible with the 'body' field.
23→   */
24→  bodyPatch?: Record<string, string | number | boolean | null>;
25→  /**
26→   * Request overrides.
27→   * If defined, the real request will be sent with the overrides.
28→   * Not compatible with the 'body' field.
29→   */
30→  request?: {
31→    /**
32→     * The new URL to send the real request.
33→     */
34→    url?: string;
35→    /**
36→     * The new request query params, defined as key-value pairs.
37→     */
38→    query?: Record<string, string | number | null>;
39→    /**
40→     * The new request headers, defined as key-value pairs.
41→     */
42→    headers?: Record<string, string | null>;
43→    /**
44→     * The new request body, defined as a string or JSON.
45→     */
46→    body?: string | null | Record<string, unknown> | Array<unknown>;
47→    /**
48→     * The new request body patch, defined as a key-value pairs.
49→     */
50→    bodyPatch?: Record<string, string | number | boolean | null>;
51→  };
52→  /**
53→   * The delay in milliseconds before sending the response.
54→   */
55→  delay?: number;
56→  /**
57→   * Flag to output debug info on server.
58→   */
59→  debug?: boolean;
60→};
61→
62→export type MockRequestOverrides = NonNullable<MockResponseSchema['request']>;
63→export type MockResponseSchemaInit = number | MockResponseSchema;
64→
65→export function buildMockResponseSchema(init: MockResponseSchemaInit): MockResponseSchema {
66→  const initObj = toMockResponseSchemaObject(init);
67→  assertSchema(initObj);
68→
69→  return Object.assign({}, initObj);
70→}
71→
72→export function toMockResponseSchemaObject(init: MockResponseSchemaInit) {
73→  return typeof init === 'number' ? { status: init } : init;
74→}
75→
76→function assertSchema(schema: MockResponseSchema) {
77→  const isStaticResponse = schema.status || schema.body;
78→  const isPatchedResponse = schema.request || schema.bodyPatch;
79→
80→  if (isStaticResponse && isPatchedResponse) {
81→    throw new Error('Ambiguous schema: is it static mock or patched response?');
82→  }
83→}
