 1→/**
 2→ * Declarative Mocking Protocol.
 3→ *
 4→ * This protocol is used to declaratively define mocks, that can be passed over the wire.
 5→ * Request schema is used to match the request.
 6→ * Response schema is used to generate the response.
 7→ */
 8→
 9→import { MockRequestSchema, MockRequestSchemaInit, buildMockRequestSchema } from './request-schema';
10→import {
11→  MockResponseSchema,
12→  MockResponseSchemaInit,
13→  buildMockResponseSchema,
14→} from './response-schema';
15→
16→export * from './request-schema';
17→export * from './response-schema';
18→
19→export type MockSchema = {
20→  reqSchema: MockRequestSchema;
21→  resSchema: MockResponseSchema;
22→};
23→
24→export type MockMatchResult = {
25→  mockSchema: MockSchema;
26→  req: Request;
27→  params: Record<string, string>;
28→};
29→
30→export function buildMockSchema(
31→  reqSchema: MockRequestSchemaInit,
32→  resSchema: MockResponseSchemaInit,
33→): MockSchema {
34→  return {
35→    reqSchema: buildMockRequestSchema(reqSchema),
36→    resSchema: buildMockResponseSchema(resSchema),
37→  };
38→}
