 1→/**
 2→ * RequestMatcher class.
 3→ * The same as URLPattern, but for matching the whole HTTP request.
 4→ * See: https://developer.mozilla.org/en-US/docs/Web/API/URL_Pattern_API
 5→ * See: https://developer.chrome.com/docs/web-platform/urlpattern
 6→ *
 7→ * todo: move to a separate package.
 8→ */
 9→
10→import { MockRequestSchema } from '../protocol';
11→import { UrlMatcher } from './matchers/url';
12→import { BodyMatcher } from './matchers/body';
13→import { MatchingContext } from './context';
14→import { MethodMatcher } from './matchers/method';
15→import { QueryMatcher } from './matchers/query';
16→import { HeadersMatcher } from './matchers/headers';
17→
18→export class RequestMatcher {
19→  private methodMatcher: MethodMatcher;
20→  private urlMatcher: UrlMatcher;
21→  private queryMatcher: QueryMatcher;
22→  private headersMatcher: HeadersMatcher;
23→  private bodyMatcher: BodyMatcher;
24→
25→  constructor(
26→    public schema: MockRequestSchema,
27→    private debug?: boolean,
28→  ) {
29→    this.methodMatcher = new MethodMatcher(this.schema);
30→    this.urlMatcher = new UrlMatcher(this.schema);
31→    this.queryMatcher = new QueryMatcher(this.schema);
32→    this.headersMatcher = new HeadersMatcher(this.schema);
33→    this.bodyMatcher = new BodyMatcher(this.schema);
34→
35→    if (schema.debug) this.debug = true;
36→    this.ensureSingleQuerySource();
37→  }
38→
39→  // eslint-disable-next-line visual/complexity
40→  async match(req: Request) {
41→    const ctx = new MatchingContext(req);
42→    try {
43→      const matched =
44→        this.methodMatcher.match(ctx) &&
45→        this.urlMatcher.match(ctx) &&
46→        this.queryMatcher.match(ctx) &&
47→        this.headersMatcher.match(ctx) &&
48→        (await this.bodyMatcher.match(ctx));
49→
50→      ctx.logDone(matched);
51→
52→      return matched ? ctx.params : null;
53→    } finally {
54→      // eslint-disable-next-line no-console
55→      if (this.debug) console.log(ctx.logs.join('\n'));
56→    }
57→  }
58→
59→  private ensureSingleQuerySource() {
60→    if (this.urlMatcher.hasQuery && this.queryMatcher.hasQuery) {
61→      throw new Error(
62→        `Query parameters should be defined either in the URL pattern or in the 'query' field.`,
63→      );
64→    }
65→  }
66→}
