 1→export class MatchingContext {
 2→  logs: string[] = [];
 3→  params: Record<string, string> = {};
 4→  #searchParams?: URLSearchParams;
 5→
 6→  constructor(public req: Request) {
 7→    this.logs.push(`Matching request: ${req.method} ${req.url}`);
 8→  }
 9→
10→  get searchParams() {
11→    if (!this.#searchParams) {
12→      this.#searchParams = new URL(this.req.url).searchParams;
13→    }
14→    return this.#searchParams;
15→  }
16→
17→  log(result: boolean, entity: string, expected: unknown, actual: unknown) {
18→    const icon = result ? '✅' : '❌';
19→    this.logs.push(`${icon} Expected ${entity}: ${expected}`);
20→    this.logs.push(`${' '.repeat(4)} Actual ${entity}: ${actual}`);
21→  }
22→
23→  logDone(matched: boolean) {
24→    this.logs.push(`Request ${matched ? 'matched' : 'not matched'}.`);
25→  }
26→
27→  appendParams(groups: Record<string, string | undefined> = {}) {
28→    Object.keys(groups).forEach((key) => {
29→      const isNamedGroup = !/^\d+$/.test(key);
30→      if (isNamedGroup) this.params[key] = groups[key]!;
31→    });
32→  }
33→}
