  1→/**
  2→ * Response builder class.
  3→ */
  4→import { STATUS_CODES } from 'node:http';
  5→import { MockMatchResult } from '../protocol';
  6→import { patchObject, wait } from './utils';
  7→import {
  8→  cloneWithPlaceholders,
  9→  replacePlaceholders,
 10→  stringifyWithPlaceholders,
 11→} from './placeholders';
 12→import { RequestPatcher } from '../request-patcher';
 13→
 14→// Universal shape for response object.
 15→export type ResponseLike = {
 16→  status: number;
 17→  statusText: string;
 18→  headers: Headers;
 19→  arrayBuffer: () => Promise<ArrayBuffer>;
 20→  json: () => Promise<Record<string, unknown>>;
 21→};
 22→
 23→export type ResponseBuilderCallbacks = {
 24→  bypass: (req: Request) => Promise<ResponseLike>;
 25→};
 26→
 27→export type ResponseBuilderResult = {
 28→  status: number;
 29→  statusText: string;
 30→  headers: Headers;
 31→  body: string | ArrayBuffer | null;
 32→};
 33→
 34→export class ResponseBuilder {
 35→  private status = 200;
 36→  private statusText = 'OK';
 37→  private headers = new Headers();
 38→  private body: string | ArrayBuffer | null = null;
 39→
 40→  constructor(
 41→    private matchResult: MockMatchResult,
 42→    private callbacks: ResponseBuilderCallbacks,
 43→  ) {}
 44→
 45→  private get resSchema() {
 46→    return this.matchResult.mockSchema.resSchema;
 47→  }
 48→
 49→  private get params() {
 50→    return this.matchResult.params;
 51→  }
 52→
 53→  private get req() {
 54→    return this.matchResult.req;
 55→  }
 56→
 57→  async build(): Promise<ResponseBuilderResult> {
 58→    if (this.needsRealRequest()) {
 59→      await this.setPatchedResponse();
 60→    } else {
 61→      this.setStaticResponse();
 62→    }
 63→
 64→    await this.wait();
 65→
 66→    return {
 67→      status: this.status,
 68→      statusText: this.statusText,
 69→      headers: this.headers,
 70→      body: this.body,
 71→    };
 72→  }
 73→
 74→  private needsRealRequest() {
 75→    return this.resSchema.request || this.resSchema.bodyPatch;
 76→  }
 77→
 78→  private async setPatchedResponse() {
 79→    const res = await this.sendRealRequest();
 80→
 81→    this.setStatus(res.status, res.statusText);
 82→    this.setHeaders(res.headers);
 83→
 84→    // remove content-encoding header, otherwise error: Decompression failed
 85→    this.headers.delete('content-encoding');
 86→
 87→    await this.setPatchedBody(res);
 88→  }
 89→
 90→  private setStaticResponse() {
 91→    if (this.resSchema.status) this.setStatus(this.resSchema.status);
 92→    this.setHeaders();
 93→    this.setStaticBody();
 94→  }
 95→
 96→  private setStatus(status: number, statusText?: string) {
 97→    this.status = status;
 98→    this.statusText = statusText || STATUS_CODES[status] || 'Unknown';
 99→  }
100→
101→  private async sendRealRequest() {
102→    const { request: requestOverrides } = this.resSchema;
103→    const req = requestOverrides
104→      ? await new RequestPatcher(this.req, requestOverrides, this.params).patch()
105→      : this.req;
106→
107→    return this.callbacks.bypass(req);
108→  }
109→
110→  private setHeaders(origHeaders?: Headers) {
111→    // Important to use Object.fromEntries(), otherwise headers become empty inside msw.
112→    // See: https://github.com/mswjs/msw/blob/main/src/core/utils/HttpResponse/decorators.ts#L20
113→    this.headers = new Headers(Object.fromEntries(origHeaders || []));
114→
115→    Object.entries(this.resSchema.headers || {}).forEach(([key, value]) => {
116→      if (value) {
117→        value = replacePlaceholders(value, this.params);
118→        this.headers.set(key, value);
119→      } else {
120→        this.headers.delete(key);
121→      }
122→    });
123→  }
124→
125→  private async setPatchedBody(res: ResponseLike) {
126→    const { bodyPatch } = this.resSchema;
127→    if (bodyPatch) {
128→      // todo: match status? If response status is not 200, should we patch it?
129→      // todo: handle parse error
130→      const actualBody = await res.json();
131→      const bodyPatchFinal = cloneWithPlaceholders(bodyPatch, this.params);
132→      patchObject(actualBody, bodyPatchFinal);
133→      this.setBodyAsString(JSON.stringify(actualBody), 'application/json');
134→    } else {
135→      this.body = await res.arrayBuffer();
136→    }
137→  }
138→
139→  private setStaticBody() {
140→    const { body } = this.resSchema;
141→    if (!body) return;
142→    if (typeof body === 'string') {
143→      const newBody = replacePlaceholders(body, this.params);
144→      this.setBodyAsString(newBody, 'text/plain');
145→    } else {
146→      const newBody = stringifyWithPlaceholders(body, this.params);
147→      this.setBodyAsString(newBody, 'application/json');
148→    }
149→  }
150→
151→  private setBodyAsString(body: string, contentType: string) {
152→    this.body = body;
153→
154→    if (!this.headers.has('content-type')) {
155→      this.headers.set('content-type', contentType);
156→    }
157→
158→    const contentLength = body ? new Blob([body]).size.toString() : '0';
159→    this.headers.set('content-length', contentLength);
160→  }
161→
162→  private async wait() {
163→    const { delay } = this.resSchema;
164→    if (delay) await wait(delay);
165→  }
166→}
