 1→/**
 2→ * A module to replace placeholders {{var}} in the string.
 3→ * Can be also used for objects within JSON.stringify replacer.
 4→ * Supports type hints, see tests.
 5→ */
 6→
 7→/* eslint-disable visual/complexity */
 8→
 9→export function cloneWithPlaceholders<T extends object>(
10→  obj: T,
11→  variables: Record<string, string> = {},
12→) {
13→  return JSON.parse(stringifyWithPlaceholders(obj, variables)) as T;
14→}
15→
16→export function stringifyWithPlaceholders(obj: object, variables: Record<string, string> = {}) {
17→  return JSON.stringify(obj, (_, value) => {
18→    return typeof value === 'string'
19→      ? replacePlaceholders(value, variables, { useTypes: true })
20→      : value;
21→  });
22→}
23→
24→type Result<T extends boolean> = T extends true ? string | number | boolean : string;
25→export function replacePlaceholders<T extends boolean = false>(
26→  value: string,
27→  variables: Record<string, string>,
28→  opts?: { useTypes?: T },
29→): Result<T> {
30→  if (Object.keys(variables).length === 0) return value;
31→
32→  // Find all placeholder matches
33→  const matches = [...value.matchAll(/\{\{\s*(\w+)(?::\s*(number|boolean))?\s*\}\}/g)];
34→  const firstMatch = matches[0];
35→
36→  // No placeholders found
37→  if (!firstMatch) return value;
38→
39→  // Example: { value: '{{id}}' }
40→  const isOnlyPlaceholder = matches.length === 1 && value.trim() === firstMatch[0];
41→
42→  // If the whole value is a single placeholder, apply type conversion
43→  // Multiple placeholders -> always replace with string
44→  return opts?.useTypes && isOnlyPlaceholder
45→    ? (replaceSinglePlaceholder(firstMatch, value, variables) as Result<T>)
46→    : replaceMultiplePlaceholders(matches, value, variables);
47→}
48→
49→function replaceSinglePlaceholder(
50→  match: RegExpExecArray,
51→  value: string,
52→  variables: Record<string, string | undefined>,
53→) {
54→  const [, key, typeHint] = match;
55→
56→  if (!key) return value;
57→
58→  const replacement = variables[key];
59→  if (replacement === undefined) return value;
60→
61→  if (typeHint === 'number') {
62→    const number = Number(replacement);
63→    if (!Number.isNaN(number)) return number;
64→  }
65→
66→  if (typeHint === 'boolean') {
67→    if (replacement === '' || replacement.toLowerCase() === 'false') return false;
68→    return true;
69→  }
70→
71→  return replacement ?? value;
72→}
73→
74→function replaceMultiplePlaceholders(
75→  matches: RegExpMatchArray[],
76→  value: string,
77→  variables: Record<string, string>,
78→) {
79→  for (const [match, key] of matches) {
80→    if (!key || variables[key] === undefined) continue;
81→    value = value.replaceAll(match, variables[key]);
82→  }
83→  return value;
84→}
