 1→/**
 2→ * URL matcher.
 3→ */
 4→import 'urlpattern-polyfill';
 5→import { MockRequestSchema } from '../../protocol';
 6→import { MatchingContext } from '../context';
 7→
 8→export class UrlMatcher {
 9→  private matcher: URLPattern | RegExp;
10→  public hasQuery = false;
11→
12→  constructor(private schema: MockRequestSchema) {
13→    this.matcher =
14→      this.schema.patternType === 'regexp' ? this.buildRegexpMatcher() : this.buildPatternMatcher();
15→  }
16→
17→  match(ctx: MatchingContext) {
18→    const { req } = ctx;
19→
20→    const shouldTrimSearchParams = Boolean(this.schema.query);
21→    const url = shouldTrimSearchParams ? trimSearchParams(req.url) : req.url;
22→
23→    const result =
24→      this.matcher instanceof RegExp
25→        ? this.matchRegexp(ctx, url, this.matcher)
26→        : this.matchPattern(ctx, url, this.matcher);
27→
28→    ctx.log(result, `URL`, this.schema.url, `${url}${url !== req.url ? ' (query trimmed)' : ''}`);
29→
30→    return result;
31→  }
32→
33→  private matchRegexp(ctx: MatchingContext, url: string, regexp: RegExp) {
34→    const result = url.match(regexp);
35→    if (result) ctx.appendParams(result.groups);
36→    return Boolean(result);
37→  }
38→
39→  private matchPattern(ctx: MatchingContext, url: string, pattern: URLPattern) {
40→    const result = pattern.exec(url);
41→    if (!result) return false;
42→
43→    const keys = Object.keys(result) as Array<keyof typeof result>;
44→    keys.forEach((key) => {
45→      const value = result[key];
46→      if ('groups' in value) ctx.appendParams(value.groups);
47→    });
48→
49→    return true;
50→  }
51→
52→  private buildRegexpMatcher() {
53→    const { url } = this.schema;
54→    this.hasQuery = url.includes('\\?');
55→    return regexpFromString(url);
56→  }
57→
58→  private buildPatternMatcher() {
59→    const { url } = this.schema;
60→    const urlPattern = new URLPattern(url);
61→    this.hasQuery = urlPattern.search !== '*';
62→    return urlPattern;
63→  }
64→}
65→
66→function regexpFromString(s: string) {
67→  const source = s.slice(1, s.lastIndexOf('/'));
68→  const flags = s.slice(s.lastIndexOf('/') + 1);
69→  return new RegExp(source, flags);
70→}
71→
72→function trimSearchParams(url: string) {
73→  const urlObj = new URL(url);
74→  urlObj.search = '';
75→  return urlObj.toString();
76→}
