 1→/**
 2→ * Query matcher.
 3→ */
 4→import { MockRequestSchema } from '../../protocol';
 5→import { MatchingContext } from '../context';
 6→
 7→export class QueryMatcher {
 8→  private expectedQuery: Record<string, string | number | null>;
 9→
10→  constructor(private schema: MockRequestSchema) {
11→    this.expectedQuery = this.schema.query || {};
12→  }
13→
14→  get hasQuery() {
15→    return Object.keys(this.expectedQuery).length > 0;
16→  }
17→
18→  match(ctx: MatchingContext) {
19→    return Object.keys(this.expectedQuery).every((key) => this.matchQueryParam(ctx, key));
20→  }
21→
22→  private matchQueryParam(ctx: MatchingContext, name: string) {
23→    // todo: handle multi-value params in expectedQuery
24→    const expectedValue = this.expectedQuery[name]?.toString() ?? null;
25→    const actualValues = ctx.searchParams.getAll(name);
26→
27→    const result =
28→      expectedValue === null ? actualValues.length === 0 : actualValues.includes(expectedValue);
29→
30→    ctx.log(result, `query param "${name}"`, expectedValue, actualValues.join(','));
31→
32→    return result;
33→  }
34→}
