  1→/**
  2→ * Module to patch fetch request.
  3→ */
  4→
  5→import { MockRequestOverrides } from '../protocol';
  6→import {
  7→  cloneWithPlaceholders,
  8→  replacePlaceholders,
  9→  stringifyWithPlaceholders,
 10→} from '../response-builder/placeholders';
 11→import { patchObject } from '../response-builder/utils';
 12→
 13→export class RequestPatcher {
 14→  private url: URL;
 15→  private headers: Headers;
 16→  private body?: RequestInit['body'];
 17→
 18→  constructor(
 19→    private req: Request,
 20→    private overrides: MockRequestOverrides,
 21→    private params: Record<string, string> = {},
 22→  ) {
 23→    this.url = new URL(req.url);
 24→    this.headers = new Headers(req.headers);
 25→  }
 26→
 27→  async patch() {
 28→    this.patchUrl();
 29→    this.patchQuery();
 30→    this.patchHeaders();
 31→    await this.patchBody();
 32→
 33→    return this.buildRequest();
 34→  }
 35→
 36→  private patchUrl() {
 37→    const { url } = this.overrides;
 38→    if (!url) return;
 39→
 40→    const newUrl = replacePlaceholders(url, this.params);
 41→    this.url = new URL(newUrl);
 42→  }
 43→
 44→  private patchQuery() {
 45→    const { query } = this.overrides;
 46→    if (!query) return;
 47→
 48→    Object.keys(query).forEach((key) => {
 49→      const value = query[key];
 50→      if (value) {
 51→        this.url.searchParams.set(key, String(value));
 52→      } else {
 53→        this.url.searchParams.delete(key);
 54→      }
 55→    });
 56→  }
 57→
 58→  private patchHeaders() {
 59→    this.headers.set('content-encoding', 'identity');
 60→    Object.entries(this.overrides.headers || {}).forEach(([key, value]) => {
 61→      if (value) {
 62→        this.headers.set(key, String(value));
 63→      } else {
 64→        this.headers.delete(key);
 65→      }
 66→    });
 67→  }
 68→
 69→  // eslint-disable-next-line max-statements
 70→  private async patchBody() {
 71→    const { body, bodyPatch } = this.overrides;
 72→
 73→    if (body === null) {
 74→      this.body = null;
 75→      return;
 76→    }
 77→
 78→    if (body) {
 79→      if (typeof body === 'string') {
 80→        const newBody = replacePlaceholders(body, this.params);
 81→        this.setBodyAsString(newBody, 'text/plain');
 82→      } else {
 83→        const newBody = stringifyWithPlaceholders(body, this.params);
 84→        this.setBodyAsString(newBody, 'application/json');
 85→      }
 86→    } else if (bodyPatch) {
 87→      const actualBody = await this.req.json();
 88→      const bodyPatchFinal = cloneWithPlaceholders(bodyPatch, this.params);
 89→      patchObject(actualBody, bodyPatchFinal);
 90→      this.setBodyAsString(JSON.stringify(actualBody), 'application/json');
 91→    }
 92→  }
 93→
 94→  private setBodyAsString(body: string, contentType: string) {
 95→    this.body = body;
 96→
 97→    if (!this.headers.has('content-type')) {
 98→      this.headers.set('content-type', contentType);
 99→    }
100→
101→    const contentLength = body ? new Blob([body]).size.toString() : '0';
102→    this.headers.set('content-length', contentLength);
103→  }
104→
105→  private buildRequest() {
106→    const { req } = this;
107→    return new Request(this.url, {
108→      headers: this.headers,
109→      body: this.body,
110→      method: req.method,
111→      mode: req.mode,
112→      credentials: req.credentials,
113→      cache: req.cache,
114→      redirect: req.redirect,
115→      referrer: req.referrer,
116→      integrity: req.integrity,
117→      keepalive: req.keepalive,
118→      signal: req.signal,
119→    });
120→  }
121→}
