 1→/**
 2→ * Body matcher.
 3→ */
 4→import isMatch from 'lodash/isMatch';
 5→import { MockRequestSchema } from '../../protocol';
 6→import { MatchingContext } from '../context';
 7→
 8→export class BodyMatcher {
 9→  constructor(private schema: MockRequestSchema) {}
10→
11→  private get expectedBody() {
12→    return this.schema.body;
13→  }
14→
15→  private get expectedBodyStr() {
16→    return typeof this.expectedBody === 'string'
17→      ? this.expectedBody
18→      : JSON.stringify(this.expectedBody);
19→  }
20→
21→  async match(ctx: MatchingContext) {
22→    if (!this.expectedBody) return true;
23→
24→    const actualBodyStream = this.schema.body;
25→    if (!actualBodyStream) {
26→      ctx.log(false, `body`, this.expectedBodyStr, `null`);
27→      return false;
28→    }
29→
30→    if (typeof this.expectedBody === 'string') {
31→      return this.matchAsString(ctx, this.expectedBody);
32→    } else {
33→      return this.matchAsObject(ctx, this.expectedBody);
34→    }
35→  }
36→
37→  private async matchAsString(ctx: MatchingContext, expectedBody: string) {
38→    const actualBody = await ctx.req.clone().text();
39→    const result = actualBody === expectedBody;
40→    ctx.log(result, `body`, expectedBody, trimLongString(actualBody));
41→
42→    return result;
43→  }
44→
45→  private async matchAsObject(
46→    ctx: MatchingContext,
47→    expectedBody: Record<string, unknown> | unknown[],
48→  ) {
49→    const actualBody = await ctx.req.clone().text();
50→    const actualBodyParsed = jsonParseSafe(actualBody);
51→
52→    if (!actualBodyParsed) {
53→      ctx.log(false, `body`, this.expectedBodyStr, trimLongString(actualBody));
54→      return false;
55→    }
56→
57→    const result = isMatch(actualBodyParsed, expectedBody);
58→    ctx.log(result, `body`, this.expectedBodyStr, trimLongString(actualBody));
59→
60→    return result;
61→  }
62→}
63→
64→function trimLongString(str: string, maxLength = 150) {
65→  return str.length > maxLength ? `${str.slice(0, maxLength)}...` : str;
66→}
67→
68→function jsonParseSafe(str: string) {
69→  try {
70→    return JSON.parse(str);
71→  } catch {
72→    return null;
73→  }
74→}
